import type { jsPDF } from "jspdf";

// Embedded Unicode font (DejaVu Sans, Latin+German subset) so jsPDF renders umlauts,
// €, en/em dashes and typographic quotes correctly. jsPDF's built-in "helvetica" is
// WinAnsi-only and mangles those characters. The subset was built with pyftsubset to keep
// the bundle small (~50 KB base64 per weight). See docs on jsPDF custom fonts.
export const PDF_FONT_FAMILY = "DejaVuSans";

const REGULAR_B64 =
  "";

const BOLD_B64 =
  "";

const registered = new WeakSet<jsPDF>();

/**
 * Register the embedded Unicode font on a jsPDF document and make it the active font.
 * Idempotent per document. Call once right after `new jsPDF()`.
 */
export function registerPdfFont(doc: jsPDF): void {
  if (!registered.has(doc)) {
    doc.addFileToVFS("DejaVuSans.ttf", REGULAR_B64);
    doc.addFont("DejaVuSans.ttf", PDF_FONT_FAMILY, "normal");
    doc.addFileToVFS("DejaVuSans-Bold.ttf", BOLD_B64);
    doc.addFont("DejaVuSans-Bold.ttf", PDF_FONT_FAMILY, "bold");
    registered.add(doc);
  }
  doc.setFont(PDF_FONT_FAMILY, "normal");
}
